 10	describe('LinksTable', () => {
 11	  const mockT = vi.fn((key: string) => key);
 12	  const mockOnDeleteLink = vi.fn();
 13	
 14	  const mockLinkRawData: LinkCrdResponse = {
 15	    apiVersion: 'skupper.io/v2alpha1',
 16	    kind: 'Link',
 17	    metadata: {
 18	      uid: '1',
 19	      name: 'link-1',
 20	      namespace: 'default',
 21	      resourceVersion: '1',
 22	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp
 23	    },
 24	    spec: {
 25	      cost: 1,
 26	      endpoints: []
 27	    },
 28	    status: {
 29	      remoteSiteId: 'site-1-id',
 30	      remoteSiteName: 'site-1',
 31	      conditions: [],
 32	      status: 'Ready' as StatusLinkType,
 33	      message: 'OK'
 34	    }
 35	  };
 36	
 37	  const mockTokenRawData: AccessTokenCrdResponse = {
 38	    apiVersion: 'skupper.io/v2alpha1',
 39	    kind: 'AccessToken',
 40	    metadata: {
 41	      uid: '2',
 42	      name: 'token-1',
 43	      namespace: 'default',
 44	      resourceVersion: '1',
 45	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp
 46	    },
 47	    spec: {
 48	      linkCost: 2,
 49	      url: 'test-url',
 50	      code: 'test-code',
 51	      ca: 'test-ca'
 52	    },
 53	    status: {
 54	      status: 'Error' as StatusLinkType,
 55	      message: 'Connection failed',
 56	      conditions: []
 57	    }
 58	  };
 59	
 60	  const mockLinks: Link[] = [
 61	    {
 62	      id: '1',
 63	      name: 'link-1',
