 65	      status: 'Ready',
 66	      statusMessage: 'OK',
 67	      hasError: false,
 68	      connectedTo: 'site-1',
 69	      cost: 1,
 70	      rawData: mockLinkRawData
 71	    },
 72	    {
 73	      id: '2',
 74	      name: 'token-1',
 75	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp,
 76	      status: 'Error',
 77	      statusMessage: 'Connection failed',
 78	      hasError: true,
 79	      connectedTo: 'site-2',
 80	      cost: 2,
 81	      rawData: mockTokenRawData
 82	    }
 83	  ];
 84	
 85	  it('renders links table with data', () => {
 86	    render(<LinksTable links={mockLinks} onDeleteLink={mockOnDeleteLink} t={mockT} />);
 87	
 88	    expect(screen.getByText('link-1')).toBeInTheDocument();
 89	    expect(screen.getByText('site-1')).toBeInTheDocument();
 90	    expect(screen.getByText('1')).toBeInTheDocument();
 91	    expect(screen.getByText('OK')).toBeInTheDocument();
 92	  });
 93	
 94	  it('handles delete action', () => {
 95	    render(<LinksTable links={mockLinks} onDeleteLink={mockOnDeleteLink} t={mockT} />);
 96	
 97	    const deleteButtons = screen.getAllByRole('button', { name: 'Delete' });
 98	    fireEvent.click(deleteButtons[0]);
 99	    expect(mockOnDeleteLink).toHaveBeenCalledWith('link-1');
100	  });
101	
102	  it('shows error status for token', () => {
103	    render(<LinksTable links={[mockLinks[1]]} onDeleteLink={mockOnDeleteLink} t={mockT} />);
104	
105	    expect(screen.getByText('Error')).toBeInTheDocument();
106	    expect(screen.getByText('Connection failed')).toBeInTheDocument();
107	  });
108	});
109	
110	describe('RemoteLinksTable', () => {
111	  const mockT = vi.fn((key: string) => key);
112	
113	  const mockRemoteLinks = [{ connectedTo: 'remote-site-1' }, { connectedTo: 'remote-site-2' }];
114	
115	  it('renders remote links table', () => {
116	    render(<RemoteLinksTable links={mockRemoteLinks} t={mockT} />);
117	
118	    expect(screen.getByText('remote-site-1')).toBeInTheDocument();
119	    expect(screen.getByText('remote-site-2')).toBeInTheDocument();
