 1	import { FC } from 'react';
 2	
 3	import SkTable from '@core/components/SkTable';
 4	import StatusCell from '@core/components/StatusCell';
 5	import { Link } from '@interfaces/REST.interfaces';
 6	import { SKColumn, SKComponentProps } from '@interfaces/SkTable.interfaces';
 7	import { Button } from '@patternfly/react-core';
 8	
 9	interface LinksTableProps {
10	  links: Link[];
11	  onDeleteLink: (name: string) => void;
12	  t: (key: string) => string;
13	}
14	
15	export const LinksTable: FC<LinksTableProps> = function ({ links, onDeleteLink, t }) {
16	  const columns: SKColumn<Link>[] = [
17	    {
18	      name: t('Name'),
19	      prop: 'name'
20	    },
21	    {
22	      name: t('Status'),
23	      prop: 'status',
24	      customCellName: 'StatusCell',
25	      width: 15
26	    },
27	    {
28	      name: t('Message'),
29	      prop: 'statusMessage'
30	    },
31	    {
32	      name: t('Linked to'),
33	      prop: 'connectedTo'
34	    },
35	    {
36	      name: t('Cost'),
37	      prop: 'cost'
38	    },
39	    {
40	      name: '',
41	      customCellName: 'actions',
42	      modifier: 'fitContent'
43	    }
44	  ];
45	
46	  const customCells = {
47	    StatusCell,
48	    actions: ({ data }: SKComponentProps<Link>) => (
49	      <Button onClick={() => onDeleteLink(data.name)} variant="link">
50	        {t('Delete')}
51	      </Button>
52	    )
53	  };
54	
55	  return <SkTable columns={columns} rows={links} customCells={customCells} alwaysShowPagination={false} isPlain />;
56	};
57	
58	interface RemoteLinksTableProps {
59	  links: { connectedTo: string | null }[];
60	  t: (key: string) => string;
61	}
62	
63	export const RemoteLinksTable: FC<RemoteLinksTableProps> = function ({ links, t }) {
64	  const columns: SKColumn<{ connectedTo: string | null }>[] = [
65	    {
66	      name: t('Linked to'),
67	      prop: 'connectedTo'
68	    }
69	  ];
70	
71	  return <SkTable columns={columns} rows={links} alwaysShowPagination={false} isPlain />;
72	};

