 1	import { I18nNamespace } from '@config/config';
 2	import { BaseView } from '@interfaces/REST.interfaces';
 3	import { Icon } from '@patternfly/react-core';
 4	import { CheckCircleIcon, ExclamationCircleIcon, InProgressIcon } from '@patternfly/react-icons';
 5	import { useTranslation } from 'react-i18next';
 6	
 7	interface StatusCellProps {
 8	  data: BaseView;
 9	}
10	
11	const StatusCell = function ({ data }: StatusCellProps) {
12	  const { t } = useTranslation(I18nNamespace);
13	
14	  return (
15	    <>
16	      {!data.status && (
17	        <>
18	          <Icon isInline>{<InProgressIcon />}</Icon> {t('In progress')}
19	        </>
20	      )}
21	      {data.status && (
22	        <>
23	          <Icon isInline status={data.statusAlert}>
24	            {data.hasError && <ExclamationCircleIcon />}
25	            {data.statusAlert === 'custom' && <CheckCircleIcon />}
26	            {data.statusAlert === 'success' && <CheckCircleIcon />}
27	          </Icon>{' '}
28	          {data?.status}
29	        </>
30	      )}
31	    </>
32	  );
33	};
34	
35	export default StatusCell;

