  1	import { ISO8601Timestamp, StatusLinkType } from '@interfaces/CRD_Base';
  2	import { Link } from '@interfaces/REST.interfaces';
  3	import { render, screen, fireEvent } from '@testing-library/react';
  4	import { describe, it, expect, vi } from 'vitest';
  5	
  6	import { AccessTokenCrdResponse } from '../src/console/interfaces/CRD_AccessToken';
  7	import { LinkCrdResponse } from '../src/console/interfaces/CRD_Link';
  8	import { LinksTable, RemoteLinksTable } from '../src/console/pages/tabs/Links/LinksTable';
  9	
 10	describe('LinksTable', () => {
 11	  const mockT = vi.fn((key: string) => key);
 12	  const mockOnDeleteLink = vi.fn();
 13	
 14	  const mockLinkRawData: LinkCrdResponse = {
 15	    apiVersion: 'skupper.io/v2alpha1',
 16	    kind: 'Link',
 17	    metadata: {
 18	      uid: '1',
 19	      name: 'link-1',
 20	      namespace: 'default',
 21	      resourceVersion: '1',
 22	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp
 23	    },
 24	    spec: {
 25	      cost: 1,
 26	      endpoints: []
 27	    },
 28	    status: {
 29	      remoteSiteId: 'site-1-id',
 30	      remoteSiteName: 'site-1',
 31	      conditions: [],
 32	      status: 'Ready' as StatusLinkType,
 33	      message: 'OK'
 34	    }
 35	  };
 36	
 37	  const mockTokenRawData: AccessTokenCrdResponse = {
 38	    apiVersion: 'skupper.io/v2alpha1',
 39	    kind: 'AccessToken',
 40	    metadata: {
 41	      uid: '2',
 42	      name: 'token-1',
 43	      namespace: 'default',
 44	      resourceVersion: '1',
 45	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp
 46	    },
 47	    spec: {
 48	      linkCost: 2,
 49	      url: 'test-url',
 50	      code: 'test-code',
 51	      ca: 'test-ca'
 52	    },
 53	    status: {
 54	      status: 'Error' as StatusLinkType,
 55	      message: 'Connection failed',
 56	      conditions: []
 57	    }
 58	  };
 59	
 60	  const mockLinks: Link[] = [
 61	    {
 62	      id: '1',
 63	      name: 'link-1',
 64	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp,
 65	      status: 'Ready',
 66	      statusMessage: 'OK',
 67	      hasError: false,
 68	      connectedTo: 'site-1',
 69	      cost: 1,
 70	      rawData: mockLinkRawData
 71	    },
 72	    {
 73	      id: '2',
 74	      name: 'token-1',
 75	      creationTimestamp: new Date().toISOString() as ISO8601Timestamp,
 76	      status: 'Error',
 77	      statusMessage: 'Connection failed',
 78	      hasError: true,
 79	      connectedTo: 'site-2',
 80	      cost: 2,
 81	      rawData: mockTokenRawData
 82	    }
 83	  ];
 84	
 85	  it('renders links table with data', () => {
 86	    render(<LinksTable links={mockLinks} onDeleteLink={mockOnDeleteLink} t={mockT} />);
 87	
 88	    expect(screen.getByText('link-1')).toBeInTheDocument();
 89	    expect(screen.getByText('site-1')).toBeInTheDocument();
 90	    expect(screen.getByText('1')).toBeInTheDocument();
 91	    expect(screen.getByText('OK')).toBeInTheDocument();
 92	  });
 93	
 94	  it('handles delete action', () => {
 95	    render(<LinksTable links={mockLinks} onDeleteLink={mockOnDeleteLink} t={mockT} />);
 96	
 97	    const deleteButtons = screen.getAllByRole('button', { name: 'Delete' });
 98	    fireEvent.click(deleteButtons[0]);
 99	    expect(mockOnDeleteLink).toHaveBeenCalledWith('link-1');
100	  });
101	
102	  it('shows error status for token', () => {
103	    render(<LinksTable links={[mockLinks[1]]} onDeleteLink={mockOnDeleteLink} t={mockT} />);
104	
105	    expect(screen.getByText('Error')).toBeInTheDocument();
106	    expect(screen.getByText('Connection failed')).toBeInTheDocument();
107	  });
108	});
109	
110	describe('RemoteLinksTable', () => {
111	  const mockT = vi.fn((key: string) => key);
112	
113	  const mockRemoteLinks = [{ connectedTo: 'remote-site-1' }, { connectedTo: 'remote-site-2' }];
114	
115	  it('renders remote links table', () => {
116	    render(<RemoteLinksTable links={mockRemoteLinks} t={mockT} />);
117	
118	    expect(screen.getByText('remote-site-1')).toBeInTheDocument();
119	    expect(screen.getByText('remote-site-2')).toBeInTheDocument();
120	  });
121	
122	  it('handles null connectedTo value', () => {
123	    const linksWithNull = [{ connectedTo: null }, { connectedTo: 'remote-site' }];
124	
125	    render(<RemoteLinksTable links={linksWithNull} t={mockT} />);
126	
127	    expect(screen.getByText('remote-site')).toBeInTheDocument();
128	  });
129	});

